{"method_body":"{
  var mid := |str| / 2;
  if |str| % 2 == 1 {
    middle_str := str[mid .. mid + 1];
    assert |middle_str| == 1;
    assert middle_str[0] == str[mid];
  } else {
    assert |str| % 2 == 0;
    assert 2 <= |str|;
    assert 1 <= mid;
    assert mid + 1 <= |str|;
    middle_str := str[mid - 1 .. mid + 1];
    assert |middle_str| == 2;
  }
}"}
